INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (10, 0, 20001, 20, "", 320, 2, 23001, "", 0, 0);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (1, 0, 40011, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 321, 2, 24001, "リリ", 125801, 1);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (2, 0, 40011, 1, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 322, 2, 24001, "クリア", 126001, 1);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (3, 0, 40011, 1, "んーと。\nこれ、あげる。\nはい", 323, 2, 24001, "プレシア", 126101, 1);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (4, 0, 40011, 1, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 324, 2, 24001, "リリ", 125801, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (5, 0, 40011, 1, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 325, 2, 24001, "クリア", 126001, 2);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES (6, 0, 40011, 1, "お兄。\nきてくれて、うれしい", 326, 2, 24001, "プレシア", 126101, 2);
